describe('loadChangelogDecisions', () => {
  let tmpDir: string, pluginDir: string;
  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'ork-dh-cl-'));
    pluginDir = fs.mkdtempSync(path.join(os.tmpdir(), 'ork-dh-p-'));
    vi.mocked(getProjectDir).mockReturnValue(tmpDir);
    vi.mocked(getPluginRoot).mockReturnValue(pluginDir);
  });
  afterEach(() => { fs.rmSync(tmpDir, { recursive: true, force: true }); fs.rmSync(pluginDir, { recursive: true, force: true }); });

  it('returns [] when CHANGELOG missing', () => { expect(loadChangelogDecisions()).toEqual([]); });
  it('parses and returns decisions', () => {
    fs.writeFileSync(path.join(pluginDir, 'CHANGELOG.md'), CHANGELOG);
    expect(loadChangelogDecisions().length).toBeGreaterThan(0);
  });
  it('uses cache when hash matches', () => {
    fs.writeFileSync(path.join(pluginDir, 'CHANGELOG.md'), CHANGELOG);
    const cacheDir = path.join(tmpDir, '.claude', 'feedback');
    fs.mkdirSync(cacheDir, { recursive: true });
    fs.writeFileSync(path.join(cacheDir, 'changelog-decisions.json'),
      JSON.stringify({ changelogHash: hashString(CHANGELOG).slice(0, 16), decisions: [makeDecision({ summary: 'Cached' })] }));
    expect(loadChangelogDecisions()[0].summary).toBe('Cached');
  });
  it('re-parses when cache stale', () => {
    fs.writeFileSync(path.join(pluginDir, 'CHANGELOG.md'), CHANGELOG);
    const cacheDir = path.join(tmpDir, '.claude', 'feedback');
    fs.mkdirSync(cacheDir, { recursive: true });
    fs.writeFileSync(path.join(cacheDir, 'changelog-decisions.json'), JSON.stringify({ changelogHash: 'stale', decisions: [] }));
    expect(loadChangelogDecisions().length).toBe(8);
  });
});

