describe('aggregateDecisions', () => {
  let tmpDir: string, pluginDir: string;
  beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'ork-dh-a-'));
    pluginDir = fs.mkdtempSync(path.join(os.tmpdir(), 'ork-dh-ap-'));
    vi.mocked(getProjectDir).mockReturnValue(tmpDir);
    vi.mocked(getPluginRoot).mockReturnValue(pluginDir);
    vi.mocked(isAgentTeamsActive).mockReturnValue(false);
  });
  afterEach(() => { fs.rmSync(tmpDir, { recursive: true, force: true }); fs.rmSync(pluginDir, { recursive: true, force: true }); });

  it('aggregates and sorts descending', async () => {
    const d = path.join(tmpDir, '.claude', 'context', 'knowledge', 'decisions');
    fs.mkdirSync(d, { recursive: true });
    fs.writeFileSync(path.join(d, 'active.json'), JSON.stringify([{ id: 's1', summary: 'S', date: '2026-03-15' }]));
    fs.writeFileSync(path.join(pluginDir, 'CHANGELOG.md'), CHANGELOG);
    const r = await aggregateDecisions();
    expect(r.metadata.totalDecisions).toBeGreaterThan(1);
    expect(r.metadata.sources.session).toBe(1);
    for (let i = 1; i < r.decisions.length; i++) {
      expect(new Date(r.decisions[i - 1].date).getTime()).toBeGreaterThanOrEqual(new Date(r.decisions[i].date).getTime());
    }
  });
  it('returns empty when no sources', async () => {
    const r = await aggregateDecisions();
    expect(r.metadata.totalDecisions).toBe(0);
  });
});

