describe('filterDecisions', () => {
  const ds = [
    makeDecision({ id: 'd1', ccVersion: '2.1.80', category: 'hooks', impact: 'high', source: 'changelog', date: '2026-03-01' }),
    makeDecision({ id: 'd2', ccVersion: '2.1.70', category: 'security', impact: 'low', source: 'session', date: '2026-02-01' }),
    makeDecision({ id: 'd3', ccVersion: '2.1.80', category: 'hooks', impact: 'medium', source: 'changelog', date: '2026-01-15' }),
  ];
  it('by ccVersion', () => { expect(filterDecisions(ds, { ccVersion: '2.1.80' })).toHaveLength(2); });
  it('by category (case-insensitive)', () => { expect(filterDecisions(ds, { category: 'HOOKS' })).toHaveLength(2); });
  it('by impact', () => { expect(filterDecisions(ds, { impact: 'high' })).toHaveLength(1); });
  it('by source', () => { expect(filterDecisions(ds, { source: 'session' })).toHaveLength(1); });
  it('by days', () => { expect(filterDecisions(ds, { days: 99999 })).toHaveLength(3); });
  it('limit', () => { expect(filterDecisions(ds, { limit: 1 })).toHaveLength(1); });
  it('combined', () => { expect(filterDecisions(ds, { ccVersion: '2.1.80', impact: 'high' })[0].id).toBe('d1'); });
  it('empty opts returns all', () => { expect(filterDecisions(ds, {})).toHaveLength(3); });
});

